class Solution:
    def selfDividingNumbers(self, left, right):
        res = []
        for v in range(left, right + 1):
            x = v
            ok = True
            while x:
                d = x % 10
                if d == 0 or v % d != 0:
                    ok = False
                    break
                x //= 10
            if ok:
                res.append(v)
        return res

