var selfDividingNumbers = function(left, right) {
    const res = [];
    for (let v = left; v <= right; v++) {
        let x = v, ok = true;
        while (x > 0) {
            const d = x % 10;
            if (d === 0 || v % d !== 0) { ok = false; break; }
            x = Math.floor(x / 10);
        }
        if (ok) res.push(v);
    }
    return res;
};
